import { ExternalTokenizer } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { ExistsOperator } from '../parser.terms.js';

const { ASTERISK, BANG, EOF, EQUALS, SPACE, CLOSING_BRACKET, BACKSLASH } =
  characterCodes;

/** @internal */
export const existsTokenizer = new ExternalTokenizer((inputStream) => {
  let currCharCode = inputStream.peek(0);

  if (currCharCode === BANG) {
    currCharCode = inputStream.advance();
  }

  // Character is not '=' -> definitely not an exists operator.
  if (currCharCode !== EQUALS) {
    return;
  }

  // If the equals is followed by a space, it may still be a valid exists operator.
  // Advance the stream and continue checking.
  if (inputStream.peek(1) === SPACE) {
    inputStream.advance();
  }

  const endOfExists = inputStream.peek(2);
  // If the next character is an asterisk at the end of the input, followed by a space
  // or a group's closing parenthesis, we have a match and accept the token.
  if (
    inputStream.peek(1) === ASTERISK &&
    (endOfExists === EOF ||
      endOfExists === SPACE ||
      endOfExists === CLOSING_BRACKET ||
      (endOfExists === BACKSLASH && inputStream.peek(3) === EOF))
  ) {
    inputStream.advance(2);
    inputStream.acceptToken(ExistsOperator);
  }
});
